 static bool hasHardUserWithinLoop(const Loop *L, const Instruction *I) {
+  // If the instruction is not loop-invariant, any use inside the loop is
+  // considered "hard" because replacing it with its exit value would change
+  // the loop's semantics.
+  // We need to check if the instruction is actually invariant in the loop.
+  // hasLoopInvariantOperands checks if all operands are loop-invariant,
+  // but for an instruction that itself is defined in the loop, we need
+  // to check if its value is invariant across iterations.
+  // A simpler conservative check: if the instruction has any operand that
+  // is defined in the loop and is not loop-invariant, then the instruction
+  // is not loop-invariant.
+  bool IsLoopInvariant = true;
+  for (const Value *Op : I->operands()) {
+    if (const Instruction *OpInst = dyn_cast<Instruction>(Op)) {
+      if (L->contains(OpInst) && !L->isLoopInvariant(Op)) {
+        IsLoopInvariant = false;
+        break;
+      }
+    }
+  }
